Performs an approximate nearest neighbor search query in a vector index using a query
vector. By default, it returns the keys of approximate nearest neighbors. You can optionally
include the computed distance (between the query vector and each vector in the response),
the vector data, and metadata of each vector in the response.

To specify the vector index, you can either use both the vector bucket name and the vector
index name, or use the vector index Amazon Resource Name (ARN).

### Permissions

You must have the `s3vectors:QueryVectors` permission to use this operation. Additional
permissions are required based on the request parameters you specify:

- With only `s3vectors:QueryVectors` permission, you can retrieve vector keys of approximate
  nearest neighbors and computed distances between these vectors. This permission is
  sufficient only when you don't set any metadata filters and don't request vector data or
  metadata (by keeping the `returnMetadata` parameter set to `false` or not specified).
- If you specify a metadata filter or set `returnMetadata` to true, you must have both
  `s3vectors:QueryVectors` and `s3vectors:GetVectors` permissions. The request fails with a
  `403 Forbidden error` if you request metadata filtering, vector data, or metadata without
  the `s3vectors:GetVectors` permission.

# Arguments

- `query_vector`: The query vector. Ensure that the query vector has the same dimension as
  the dimension of the vector index that's being queried. For example, if your vector index
  contains vectors with 384 dimensions, your query vector must also have 384 dimensions.
- `top_k`: The number of results to return for each query.

# Optional Parameters

Optional parameters can be passed as a `params::Dict{String,<:Any}`. Valid keys are:

- `"filter"`: Metadata filter to apply during the query. For more information about metadata
  keys, see [Metadata filtering](https://docs.aws.amazon.com/AmazonS3/latest/userguide/s3-vectors-metadata-filtering.html)
  in the *Amazon S3 User Guide*.
- `"indexArn"`: The ARN of the vector index that you want to query.
- `"indexName"`: The name of the vector index that you want to query.
- `"returnDistance"`: Indicates whether to include the computed distance in the response.
  The default value is `false`.
- `"returnMetadata"`: Indicates whether to include metadata in the response. The default
  value is `false`.
- `"vectorBucketName"`: The name of the vector bucket that contains the vector index.
"""
function query_vectors end

function query_vectors(
    queryVector, topK; aws_config::AbstractAWSConfig=current_aws_config()
)
    return s3vectors(
        "POST",
        "/QueryVectors",
        Dict{String,Any}("queryVector" => queryVector, "topK" => topK);
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function query_vectors(
    queryVector,
    topK,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return s3vectors(
        "POST",
        "/QueryVectors",
        Dict{String,Any}(
            mergewith(
                _merge,
                Dict{String,Any}("queryVector" => queryVector, "topK" => topK),
                params,
            ),
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

"""
    tag_resource(resource_arn, tags)
    tag_resource(resource_arn, tags, params::Dict{String,<:Any})

Applies one or more user-defined tags to an Amazon S3 Vectors resource or updates existing
tags. Each tag is a label consisting of a key and value pair. Tags can help you organize,
track costs for, and control access to your resources. You can add up to 50 tags for each
resource.

!!! note
    For a list of S3 resources that support tagging, see [Managing tags for Amazon S3 resources](https://docs.aws.amazon.com/AmazonS3/latest/userguide/tagging.html#manage-tags).

### Permissions

For vector buckets and vector indexes, you must have the `s3vectors:TagResource` permission
to use this operation.

# Arguments

- `resource_arn`: The Amazon Resource Name (ARN) of the Amazon S3 Vectors resource that
  you're applying tags to. The tagged resource can be a vector bucket or a vector index.
- `tags`: The user-defined tag that you want to add to the specified S3 Vectors resource.
  For more information, see [Tagging for cost allocation or attribute-based access control (ABAC)](https://docs.aws.amazon.com/AmazonS3/latest/userguide/tagging.html).
"""
function tag_resource end

function tag_resource(resourceArn, tags; aws_config::AbstractAWSConfig=current_aws_config())
    return s3vectors(
        "POST",
        "/tags/$(resourceArn)",
        Dict{String,Any}("tags" => tags);
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function tag_resource(
    resourceArn,
    tags,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return s3vectors(
        "POST",
        "/tags/$(resourceArn)",
        Dict{String,Any}(mergewith(_merge, Dict{String,Any}("tags" => tags), params));
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

"""
    untag_resource(resource_arn, tag_keys)
    untag_resource(resource_arn, tag_keys, params::Dict{String,<:Any})

Removes the specified user-defined tags from an Amazon S3 Vectors resource. You can pass one
or more tag keys.

!!! note
    For a list of S3 resources that support tagging, see [Managing tags for Amazon S3 resources](https://docs.aws.amazon.com/AmazonS3/latest/userguide/tagging.html#manage-tags).

### Permissions

For vector buckets and vector indexes, you must have the `s3vectors:UntagResource`
permission to use this operation.

# Arguments

- `resource_arn`: The Amazon Resource Name (ARN) of the Amazon S3 Vectors resource that
  you're removing tags from. The tagged resource can be a vector bucket or a vector index.
- `tag_keys`: The array of tag keys that you're removing from the S3 Vectors resource. For
  more information, see [Tagging for cost allocation or attribute-based access control (ABAC)](https://docs.aws.amazon.com/AmazonS3/latest/userguide/tagging.html).
"""
function untag_resource end

function untag_resource(
    resourceArn, tagKeys; aws_config::AbstractAWSConfig=current_aws_config()
)
    return s3vectors(
        "DELETE",
        "/tags/$(resourceArn)",
        Dict{String,Any}("tagKeys" => tagKeys);
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function untag_resource(
    resourceArn,
    tagKeys,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return s3vectors(
        "DELETE",
        "/tags/$(resourceArn)",
        Dict{String,Any}(mergewith(_merge, Dict{String,Any}("tagKeys" => tagKeys), params));
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end
